#include <iostream>
#include <cstring>
#include <algorithm>
using namespace std;
string pluss(string a,string b)
{
    int sum[505]={0}, a1[505], b1[505]={0};
    reverse(a.begin(),a.end());
    reverse(b.begin(),b.end());
    for(int i=0;i<=a.size()-1;i++)
    {
        a1[i]=a[i]-48;
    }
    for(int i=0;i<=b.size()-1;i++)
    {
        b1[i]=b[i]-48;
    }
    int len=max(a.size(),b.size());
    for(int i=0;i<=len-1;i++)
    {
        sum[i]=a1[i]+b1[i]+sum[i];
        sum[i+1]=sum[i]/10;
        sum[i]=sum[i]%10;
    }
    while(sum[len]==0&&len>0)
    {
        len--;
    }
    string sum1="";
    for(int i=len;i>=0;i--)
    {
        sum1+=(sum[i]+'0');
    }
    return sum1;
}
int main()
{
    int n;
    cin>>n;
    string a[55];
    a[1]="1";
    a[2]="2";
    for(int i=3;i<=n;i++)
    {
        a[i]=pluss(a[i-1],a[i-2]);
    }
    cout<<a[n];
}
